override fun generateAccessToken(userId: Long): String {
    val now = Date()
    return Jwts.builder()
        .subject(userId.toString())
        .claim("type", "access")
        .issuedAt(now)
        .expiration(Date(now.time + accessTokenExpiry * 1000L))
        .signWith(key)
        .compact()
}

override fun validateRefreshToken(token: String): Long? {
    val userId = refreshTokenStore[refreshTokenKey(token)] ?: return null
    return try {
        val claims = Jwts.parser()
            .verifyWith(key)
            .build()
            .parseSignedClaims(token)
            .payload
        if (claims["type"] != "refresh") return null
        userId.toLong()
    } catch (e: Exception) { null }

interface TokenPort {
    fun generateAccessToken(userId: Long): String
    fun generateRefreshToken(userId: Long): String
    fun validateRefreshToken(token: String): Long?
    fun blacklistToken(token: String)
}

override suspend fun exchangeCodeForToken(authCode: String, redirectUri: String): OAuthTokenResult {
    val webClient = webClientBuilder.build()
    val response = webClient.post()
        .uri("https://oauth2.googleapis.com/token")
        ...
        .bodyToMono(GoogleTokenResponse::class.java)
        .awaitSingle()
    return OAuthTokenResult(accessToken = response.accessToken)
}

